@@ -0,0 +1,188 @@
+import React from 'react';
+import { renderHook, act } from '@testing-library/react-hooks';
+
+import useSharesState, { SharesStateProvider } from './useSharesState';
+import { ShareType } from './interface';
+
+const wrapper: React.FC = ({ children }) => (
+    <SharesStateProvider>{children}</SharesStateProvider>
+);
+
+describe('useSharesState fallback selection', () => {
+    it('prefers most recent personal share over shared', () => {
+        const { result } = renderHook(() => useSharesState(), { wrapper });
+
+        act(() => {
+            result.current.setShares([
+                {
+                    shareId: 'personal-old',
+                    rootLinkId: 'r1',
+                    volumeId: 'v1',
+                    creator: 'u1',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    possibleKeyPackets: [],
+                    type: ShareType.default,
+                    lastAccessedAt: 1000,
+                } as any,
+                {
+                    shareId: 'shared-new',
+                    rootLinkId: 'r2',
+                    volumeId: 'v2',
+                    creator: 'u2',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    possibleKeyPackets: [],
+                    type: ShareType.standart,
+                    lastAccessedAt: 3000,
+                } as any,
+                {
+                    shareId: 'personal-new',
+                    rootLinkId: 'r3',
+                    volumeId: 'v3',
+                    creator: 'u3',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    possibleKeyPackets: [],
+                    type: ShareType.default,
+                    lastAccessedAt: 2000,
+                } as any,
+            ]);
+        });
+
+        const id = result.current.getDefaultShareId();
+        expect(id).toBe('personal-new');
+    });
+
+    it('treats ShareType.default as the only personal space', () => {
+        const { result } = renderHook(() => useSharesState(), { wrapper });
+
+        act(() => {
+            result.current.setShares([
+                {
+                    shareId: 'device-new',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    type: ShareType.device,
+                    lastAccessedAt: 5000,
+                } as any,
+                {
+                    shareId: 'personal-old',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    type: ShareType.default,
+                    lastAccessedAt: 1000,
+                } as any,
+            ]);
+        });
+
+        const id = result.current.getDefaultShareId();
+        expect(id).toBe('personal-old');
+    });
+
+    it('breaks ties by shareId ascending within personal spaces', () => {
+        const { result } = renderHook(() => useSharesState(), { wrapper });
+
+        act(() => {
+            result.current.setShares([
+                {
+                    shareId: 'personal-b',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    type: ShareType.default,
+                    lastAccessedAt: 2000,
+                } as any,
+                {
+                    shareId: 'personal-a',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    type: ShareType.default,
+                    lastAccessedAt: 2000,
+                } as any,
+            ]);
+        });
+
+        const id = result.current.getDefaultShareId();
+        expect(id).toBe('personal-a');
+    });
+
+    it('treats missing lastAccessedAt as 0 for sorting', () => {
+        const { result } = renderHook(() => useSharesState(), { wrapper });
+
+        act(() => {
+            result.current.setShares([
+                {
+                    shareId: 'personal-negative',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    type: ShareType.default,
+                    lastAccessedAt: -5,
+                } as any,
+                {
+                    shareId: 'personal-missing',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    type: ShareType.default,
+                } as any,
+            ]);
+        });
+
+        const id = result.current.getDefaultShareId();
+        expect(id).toBe('personal-missing');
+    });
+
+    it('when no personal spaces exist, picks most recent non-personal with shareId tie-break', () => {
+        const { result } = renderHook(() => useSharesState(), { wrapper });
+
+        act(() => {
+            result.current.setShares([
+                {
+                    shareId: 'shared-locked',
+                    isLocked: true,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    type: ShareType.standart,
+                    lastAccessedAt: 9999,
+                } as any,
+                {
+                    shareId: 'shared-soft-deleted',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: true,
+                    type: ShareType.standart,
+                    lastAccessedAt: 8888,
+                } as any,
+                {
+                    shareId: 'shared-b',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    type: ShareType.standart,
+                    lastAccessedAt: 1000,
+                } as any,
+                {
+                    shareId: 'shared-a',
+                    isLocked: false,
+                    isDefault: false,
+                    isVolumeSoftDeleted: false,
+                    type: ShareType.standart,
+                    lastAccessedAt: 1000,
+                } as any,
+            ]);
+        });
+
+        const id = result.current.getDefaultShareId();
+        expect(id).toBe('shared-a');
+    });
+});
+
